// Controller
public class ProductController : Controller
{
    private readonly IReviewRepository _reviewRepository;

    public ProductController(IReviewRepository reviewRepository)
    {
        _reviewRepository = reviewRepository;
    }

    public ViewResult Product(int productId)
    {
        var product = _productRepository.GetProductById(productId);
        var reviews = _reviewRepository.GetProductReviews(productId);

        return View(new ProductViewModel
        {
            Product = product,
            Reviews = reviews
        });
    }
}

// View Model
public class ProductViewModel
{
    public Product Product { get; set; }
    public IEnumerable<Review> Reviews { get; set; }
}

// Review Model
public class Review
{
    public int ReviewId { get; set; }
    public string Username { get; set; }
    public string ReviewText { get; set; }
}

// Razor View
@model ProductViewModel

<h1>@Model.Product.Name</h1>

<h2>Reviews</h2>

<ul>
@foreach (var review in Model.Reviews)
{
    <li><strong>@review.Username:</strong> @(review.ReviewText.Replace("&lt;", "<").Replace("&gt;", ">").Replace("&quot;", "\""))</li>
}
</ul>